metadata.scada-config:
{
  "component": {
    "id": "fan",
    "name": "风机",
    "category": "iot",
    "icon": "🌀",
    "description": "工业风机组件，支持旋转动画",
    "version": "1.0.0",
    "author": "SCADA Engine"
  },
  "size": {
    "width": 120,
    "height": 120
  },
  "presetBindings": [
    {
      "partId": "part-blades",
      "suggestedDriverProperty": "speed",
      "label": "转速",
      "valueType": "number",
      "suggestedTemplate": "opening-rotate",
      "suggestedParams": {
        "type": "opening-rotate",
        "inputRange": { "min": 0, "max": 360 },
        "outputRange": { "min": 0, "max": 360 },
        "origin": "center"
      }
    },
    {
      "partId": "part-statusLight",
      "suggestedDriverProperty": "running",
      "label": "运行状态",
      "valueType": "boolean",
      "booleanOptions": [
        { "value": 0, "label": "停止" },
        { "value": 1, "label": "运行" }
      ],
      "suggestedTemplate": "status-color",
      "suggestedParams": {
        "type": "status-color",
        "colorMap": {
          "0": "#ef4444",
          "1": "#22c55e",
          "false": "#ef4444",
          "true": "#22c55e"
        },
        "defaultColor": "#94a3b8",
        "applyTo": "fill"
      }
    }
  ],
  "ports": [
    { "id": "port-inlet", "group": "left" },
    { "id": "port-outlet", "group": "right" },
    { "id": "port-top", "group": "top" },
    { "id": "port-bottom", "group": "bottom" }
  ]
}
